import {
  useState,
  useEffect,
  useRef,
  useCallback,
} from "react";

/* ============================================================
   SPRITE SHEET — 5 kolom x 3 baris (idle / push / pull)
   Di project asli, ganti dengan:  const SPRITE_URL = "/sprite.png";
   ============================================================ */
const SPRITE_URL = "data:image/png;base64,";

const COLS = 5;
const ROW_IDLE = 0;
const ROW_PUSH = 1;
const ROW_PULL = 2;

/* Choreografi (ms) */
const FRAME_MS = 110; // kecepatan frame aksi
const WINDUP_MS = 180; // jeda sebelum kartu meluncur (ancang-ancang)
const SLIDE_MS = 680; // durasi slide kartu (samakan dgn CSS)

/* ============================================================
   DATA PROJECT — edit di sini saja
   ============================================================ */
const PROJECTS = [
  {
    title: "NTI Rain Calc",
    tags: ["Odoo", "Python", "QWeb", "PostgreSQL"],
    accent: "#3b2ff5",
  },
  {
    title: "NTI Siphonic Calc",
    tags: ["Odoo 18", "Python", "OWL", "SciPy", "QWeb", "PostgreSQL"],
    accent: "#3b2ff5",
  },
  {
    title: "NTI Rain Master",
    tags: ["Odoo", "Python", "OWL", "XML"],
    accent: "#3b2ff5",
  },
];

/* ============================================================
   LANTAI 3D INTERAKTIF
   Bidang grid dimiringkan dengan CSS 3D (perspective + rotateX).
   Tiap sel adalah elemen asli, jadi :hover tetap akurat mengikuti
   perspektif — sel menyala cepat saat disentuh kursor lalu
   memudar pelan (transition asimetris) sehingga meninggalkan jejak.
   ============================================================ */
const FLOOR_COLS = 90;
const FLOOR_ROWS = 52;

function Floor() {
  const cells = Array.from({ length: FLOOR_COLS * FLOOR_ROWS });
  return (
    <div className="floor-scene" aria-hidden="true">
      <div className="floor">
        {cells.map((_, i) => (
          <span key={i} className="cell" />
        ))}
      </div>
      <div className="floor-haze" />
    </div>
  );
}

/* ============================================================
   APP
   ============================================================ */
export default function PortfolioCarousel() {
  const N = PROJECTS.length;
  const [active, setActive] = useState(1);
  const [frame, setFrame] = useState({ row: ROW_IDLE, col: 0 });
  const [pose, setPose] = useState("idle"); // idle | push | pull
  const [kick, setKick] = useState(0); // gerak kecil kartu saat ancang-ancang
  const [tilt, setTilt] = useState(0); // kemiringan kartu (tepi kiri naik/turun)

  const modeRef = useRef("idle");
  const busyRef = useRef(false);
  const timersRef = useRef([]);

  const later = (fn, ms) => timersRef.current.push(setTimeout(fn, ms));

  /* ---------- idle loop: ping-pong biar halus ---------- */
  useEffect(() => {
    const seq = [0, 1, 2, 3, 4, 3, 2, 1];
    let i = 0;
    const id = setInterval(() => {
      if (modeRef.current !== "idle") return;
      i = (i + 1) % seq.length;
      setFrame({ row: ROW_IDLE, col: seq[i] });
    }, 160);
    return () => clearInterval(id);
  }, []);

  useEffect(() => () => timersRef.current.forEach(clearTimeout), []);

  /* ---------- slide + choreografi karakter ----------
     Arah dibuat konsisten secara fisik:
     - NEXT  → kartu bergerak ke KIRI  → karakter MENARIK (pull, badan condong kiri)
     - PREV  → kartu bergerak ke KANAN → karakter MENDORONG (push, tangan ke kanan)
  ---------------------------------------------------- */
  const go = useCallback(
    (dir) => {
      if (busyRef.current) return;
      busyRef.current = true;
      modeRef.current = "action";

      const row = dir > 0 ? ROW_PULL : ROW_PUSH;
      const poseName = dir > 0 ? "pull" : "push";

      // 1) ANCANG-ANCANG: pegang kartu, kartu ikut bergeser + miring
      //    pull (dir>0, geser kiri): tepi kiri TURUN  -> tilt negatif
      //    push (dir<0, geser kanan): tepi kiri NAIK  -> tilt positif
      setPose(poseName);
      setFrame({ row, col: 0 });
      later(() => setFrame({ row, col: 1 }), FRAME_MS);
      setKick(dir > 0 ? -1 : 1);
      setTilt(dir > 0 ? -1 : 1);

      // 2) LEPAS: kartu meluncur, frame aksi lanjut sampai penuh.
      //    kickX (geser samping) dilepas, tapi tilt DIPERTAHANKAN
      //    supaya kartu tetap terlihat 'diseret/didorong' selama meluncur.
      later(() => {
        setKick(0);
        setActive((a) => (a + dir + N) % N);
        for (let c = 2; c < COLS; c++) {
          later(() => setFrame({ row, col: c }), (c - 2) * FRAME_MS);
        }
      }, WINDUP_MS);

      // 2b) kartu mulai mendarat -> tilt kembali rata
      later(() => setTilt(0), WINDUP_MS + SLIDE_MS * 0.55);

      // 3) SELESAI: tahan frame terakhir sebentar, balik idle
      later(() => {
        modeRef.current = "idle";
        setPose("idle");
        setFrame({ row: ROW_IDLE, col: 0 });
      }, WINDUP_MS + SLIDE_MS - 60);

      later(() => (busyRef.current = false), WINDUP_MS + SLIDE_MS + 40);
    },
    [N]
  );

  /* ---------- keyboard ---------- */
  useEffect(() => {
    const onKey = (e) => {
      if (e.key === "ArrowRight") go(1);
      if (e.key === "ArrowLeft") go(-1);
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [go]);

  /* ---------- swipe / drag ---------- */
  const dragX = useRef(null);
  const onPointerDown = (e) => (dragX.current = e.clientX);
  const onPointerUp = (e) => {
    if (dragX.current == null) return;
    const dx = e.clientX - dragX.current;
    dragX.current = null;
    if (Math.abs(dx) > 40) go(dx < 0 ? 1 : -1);
  };

  /* offset melingkar: -1 (kiri), 0 (tengah), 1 (kanan) */
  const offsetOf = (i) => {
    let off = (i - active + N) % N;
    if (off > N / 2) off -= N;
    return off;
  };

  return (
    <div
      className="stage"
      onPointerDown={onPointerDown}
      onPointerUp={onPointerUp}
    >
      <style>{css}</style>

      {/* latar */}
      <Floor />
      <div className="blob blob-a" />
      <div className="blob blob-b" />
      <div className="blob blob-c" />

      <header className="brand">
        <span className="brand-dot" />
        wwdnn<span className="brand-thin">.dev</span>
      </header>

      {/* deck kartu */}
      <div className="deck">
        {PROJECTS.map((p, i) => {
          const off = offsetOf(i);
          const isCenter = off === 0;
          const kickX = isCenter ? kick * 16 : 0;
          // tilt: derajat kemiringan; origin di kanan -> tepi KIRI yang berayun
          const tiltDeg = isCenter ? tilt * 3.2 : 0;
          return (
            <article
              key={p.title}
              className={`card ${isCenter ? "is-center" : "is-side"}`}
              style={{
                transformOrigin: "100% 50%",
                transform: `translate(-50%, -50%) translateX(calc(${
                  off * 74
                }% + ${kickX}px)) rotate(${tiltDeg}deg) scale(${
                  isCenter ? 1 : 0.84
                })`,
                zIndex: isCenter ? 30 : 10,
                opacity: Math.abs(off) > 1 ? 0 : isCenter ? 1 : 0.55,
                filter: isCenter ? "none" : "saturate(0.7)",
                pointerEvents: isCenter ? "auto" : "none",
              }}
            >
              <div className="card-preview">
                <div className="app-icon" style={{ background: p.accent }}>
                  <span />
                </div>
              </div>
              <h2 className="card-title">{p.title}</h2>
              <div className="card-tags">
                {p.tags.map((t) => (
                  <span key={t} className="tag">
                    {t}
                  </span>
                ))}
              </div>
            </article>
          );
        })}

        {/* karakter — dijangkarkan via CSS ke sudut kiri-bawah kartu aktif.
            Kartu aktif SELALU di pusat deck (translateX 0) dengan lebar
            --card-w, jadi posisi karakter tidak perlu diukur dari DOM;
            ini yang bikin dia tidak lagi pindah-pindah. */}
        <div className={`char-anchor pose-${pose}`}>
          <div
            className="char-sprite"
            style={{
              backgroundImage: `url(${SPRITE_URL})`,
              backgroundPosition: `${frame.col * 25}% ${frame.row * 50}%`,
            }}
          />
          <div className="char-shadow" />
        </div>
      </div>

      {/* navigasi */}
      <nav className="navbar">
        <button
          className="nav-btn"
          aria-label="Sebelumnya"
          onClick={() => go(-1)}
        >
          ←
        </button>
        <div className="dots">
          {PROJECTS.map((_, i) => (
            <span key={i} className={`dot ${i === active ? "on" : ""}`} />
          ))}
        </div>
        <button className="nav-btn" aria-label="Berikutnya" onClick={() => go(1)}>
          →
        </button>
      </nav>
    </div>
  );
}

/* ============================================================
   STYLES — glassmorphism
   ============================================================ */
const css = `
@import url('https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@500;700&family=Inter:wght@400;500;600&display=swap');

* { box-sizing: border-box; margin: 0; }

.stage {
  --card-w: min(640px, 82vw);
  --accent: #3b2ff5;
  position: relative;
  width: 100%;
  min-height: 100vh;
  overflow: hidden;
  font-family: 'Inter', system-ui, sans-serif;
  background: linear-gradient(175deg, #fdfdfe 0%, #f7f8fb 60%, #f1f3f8 100%);
  display: flex;
  flex-direction: column;
  align-items: center;
  user-select: none;
  touch-action: pan-y;
}

/* ---------- lantai 3D ---------- */
.floor-scene {
  position: absolute; inset: 0;
  perspective: 780px;
  perspective-origin: 50% 32%;
  overflow: hidden;
}

.floor {
  position: absolute;
  left: 50%;
  bottom: -46%;
  width: 300%;
  height: 130%;
  transform: translateX(-50%) rotateX(66deg);
  transform-origin: 50% 0%;
  transform-style: preserve-3d;
  display: grid;
  grid-template-columns: repeat(90, 1fr);
  grid-template-rows: repeat(52, 1fr);
  /* memudar mendekati horizon */
  mask-image: linear-gradient(to bottom, transparent 0%, black 34%, black 100%);
  -webkit-mask-image: linear-gradient(to bottom, transparent 0%, black 34%, black 100%);
}

.cell {
  border-right: 1px solid rgba(75, 85, 130, 0.10);
  border-bottom: 1px solid rgba(75, 85, 130, 0.10);
  background: transparent;
  /* fade-out lambat = jejak kursor; fade-in cepat saat disentuh */
  transition: background 1.6s ease, box-shadow 1.6s ease;
}
.cell:hover {
  transition: background 0.05s ease, box-shadow 0.05s ease;
  background: rgba(91, 79, 255, 0.32);
  /* glow melebar ke sel tetangga supaya tetap terlihat walau selnya kecil */
  box-shadow: 0 0 18px 9px rgba(91, 79, 255, 0.24);
}

/* kabut putih di horizon + vignette sisi, seperti referensi */
.floor-haze {
  position: absolute; inset: 0;
  pointer-events: none;
  background:
    radial-gradient(ellipse 70% 46% at 50% 34%, rgba(255,255,255,0.95) 0%, rgba(255,255,255,0) 70%),
    linear-gradient(to right, rgba(253,253,254,0.9) 0%, rgba(253,253,254,0) 14%, rgba(253,253,254,0) 86%, rgba(253,253,254,0.9) 100%);
}

/* blob warna di belakang kaca */
.blob {
  position: absolute;
  border-radius: 50%;
  filter: blur(90px);
  opacity: 0.32;
  pointer-events: none;
}
.blob-a { width: 480px; height: 480px; background: #7c8cff; top: -140px; left: -120px; }
.blob-b { width: 420px; height: 420px; background: #b3e3ff; bottom: -160px; right: -100px; }
.blob-c { width: 300px; height: 300px; background: #ffd9ec; top: 40%; right: 18%; opacity: 0.4; }

.brand {
  position: absolute;
  top: 28px; left: 36px;
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 700;
  font-size: 20px;
  letter-spacing: -0.02em;
  color: #171a2b;
  display: flex; align-items: center; gap: 10px;
  z-index: 50;
}
.brand-thin { font-weight: 500; color: #8d93ad; }
.brand-dot {
  width: 10px; height: 10px; border-radius: 4px;
  background: var(--accent);
  box-shadow: 0 0 0 4px rgba(59,47,245,0.15);
}

/* ---------- deck ---------- */
.deck {
  position: relative;
  width: 100%;
  flex: 1;
  min-height: 78vh;
  /* PENTING: deck menutupi hampir seluruh layar — biarkan mouse
     tembus ke lantai di belakangnya. Kartu aktif tetap bisa
     di-hover karena pointer-events-nya dinyalakan lagi per kartu. */
  pointer-events: none;
}

.card {
  position: absolute;
  top: 46%; left: 50%;
  width: var(--card-w);
  padding: 22px 30px 28px;
  border-radius: 28px;
  background: rgba(255,255,255,0.48);
  border: 1px solid rgba(255,255,255,0.75);
  box-shadow:
    0 24px 60px -18px rgba(35,45,95,0.28),
    inset 0 1px 0 rgba(255,255,255,0.9);
  backdrop-filter: blur(22px) saturate(1.5);
  -webkit-backdrop-filter: blur(22px) saturate(1.5);
  transition:
    transform 0.68s cubic-bezier(0.22, 1, 0.36, 1),
    opacity 0.68s ease,
    filter 0.68s ease;
  will-change: transform;
}

.card-preview {
  height: clamp(200px, 34vh, 320px);
  border-radius: 20px;
  background: rgba(255,255,255,0.35);
  border: 1px solid rgba(255,255,255,0.8);
  box-shadow: inset 0 2px 12px rgba(120,130,180,0.10);
  display: flex; align-items: center; justify-content: center;
}

.app-icon {
  width: 58px; height: 58px;
  border-radius: 16px;
  display: flex; align-items: center; justify-content: center;
  box-shadow: 0 10px 24px -6px rgba(59,47,245,0.55);
}
.app-icon span {
  width: 18px; height: 18px;
  border: 3px solid #fff;
  border-radius: 5px;
}

.card-title {
  font-family: 'Space Grotesk', sans-serif;
  font-weight: 700;
  font-size: clamp(26px, 4.4vw, 42px);
  letter-spacing: -0.03em;
  color: #14172a;
  margin: 20px 2px 14px;
  white-space: nowrap;
  overflow: hidden;
  text-overflow: ellipsis;
}

.card-tags { display: flex; flex-wrap: wrap; gap: 8px; }
.tag {
  font-size: 13px;
  font-weight: 500;
  color: #3a3f58;
  padding: 6px 14px;
  border-radius: 999px;
  background: rgba(255,255,255,0.55);
  border: 1px solid rgba(255,255,255,0.9);
  box-shadow: 0 2px 8px rgba(60,70,120,0.06);
  backdrop-filter: blur(8px);
}

/* ---------- karakter ----------
   Kartu aktif selalu di pusat deck. Tepi KIRI kartu = 50% - (card-w / 2).
   Karakter dijangkarkan ke titik itu (left) dan ke dasar kartu (top),
   lalu digeser dengan translate agar tangannya menimpa tepi kartu dan
   kakinya menapak sejajar dasar kartu. Semua via CSS -> tidak drift.
---------------------------------- */
.char-anchor {
  position: absolute;
  z-index: 40;
  left: calc(50% - (var(--card-w) / 2));
  top: 46%;
  /* base: naikkan ke dasar kartu (setengah tinggi kartu ~ 33vh) lalu
     tarik badan sedikit ke kiri supaya tangan overlap tepi kartu */
  transform: translate(-56%, calc(33vh - 100%));
  transition: transform 0.22s cubic-bezier(0.34, 1.56, 0.64, 1);
  pointer-events: none;
}
/* PUSH: badan merangsek ke kanan, menempel kartu */
.char-anchor.pose-push {
  transform: translate(-56%, calc(33vh - 100%)) translateX(20px);
}
/* PULL: badan condong mundur ke kiri, seperti menyeret kartu */
.char-anchor.pose-pull {
  transform: translate(-56%, calc(33vh - 100%)) translateX(-22px);
}

.char-sprite {
  width: clamp(84px, 11vw, 118px);
  aspect-ratio: 260 / 340;
  background-size: 500% 300%;
  background-repeat: no-repeat;
  image-rendering: auto;
  filter: drop-shadow(0 8px 10px rgba(30,35,70,0.18));
}

.char-shadow {
  width: 72%;
  height: 12px;
  margin: -6px auto 0;
  border-radius: 50%;
  background: radial-gradient(ellipse, rgba(30,35,70,0.30), transparent 70%);
  transition: transform 0.22s ease, opacity 0.22s ease;
}
.pose-pull .char-shadow { transform: scaleX(1.25); opacity: 0.8; }
.pose-push .char-shadow { transform: scaleX(1.15); }

/* ---------- navigasi ---------- */
.navbar {
  position: relative;
  z-index: 50;
  margin: 0 0 34px;
  display: flex;
  align-items: center;
  gap: 18px;
  padding: 10px 16px;
  border-radius: 999px;
  background: rgba(255,255,255,0.5);
  border: 1px solid rgba(255,255,255,0.8);
  box-shadow: 0 14px 34px -12px rgba(35,45,95,0.25);
  backdrop-filter: blur(18px) saturate(1.4);
  -webkit-backdrop-filter: blur(18px) saturate(1.4);
}

.nav-btn {
  width: 40px; height: 40px;
  border-radius: 50%;
  border: 1px solid rgba(255,255,255,0.9);
  background: rgba(255,255,255,0.6);
  color: #2a2e45;
  font-size: 17px;
  cursor: pointer;
  transition: transform 0.18s ease, box-shadow 0.18s ease, background 0.18s ease;
}
.nav-btn:hover {
  background: #fff;
  transform: translateY(-2px);
  box-shadow: 0 8px 18px -6px rgba(35,45,95,0.3);
}
.nav-btn:active { transform: translateY(0) scale(0.94); }
.nav-btn:focus-visible { outline: 2px solid var(--accent); outline-offset: 2px; }

.dots { display: flex; gap: 8px; }
.dot {
  width: 8px; height: 8px;
  border-radius: 999px;
  background: rgba(60,70,120,0.22);
  transition: all 0.4s cubic-bezier(0.22, 1, 0.36, 1);
}
.dot.on { width: 26px; background: var(--accent); }

/* ---------- responsif & aksesibilitas ---------- */
@media (max-width: 640px) {
  .stage { --card-w: 86vw; }
  .card { padding: 16px 20px 22px; }
  /* di mobile kartu lebih tinggi relatif viewport & lebih sempit;
     tarik karakter sedikit ke dalam supaya tetap menempel tepi kartu */
  .char-anchor { transform: translate(-40%, calc(30vh - 100%)); }
  .char-anchor.pose-push { transform: translate(-40%, calc(30vh - 100%)) translateX(14px); }
  .char-anchor.pose-pull { transform: translate(-40%, calc(30vh - 100%)) translateX(-16px); }
}

@media (prefers-reduced-motion: reduce) {
  .card, .char-anchor, .dot, .cell { transition-duration: 0.01s; }
}
`;
